def solve(s: str) -> List[str]:
    res = []
    def backtrack(i, cur):
        if i == len(s):
            res.append(cur)
            return
        if s[i].isalpha():
            backtrack(i + 1, cur + s[i].lower())
            backtrack(i + 1, cur + s[i].upper())
        else:
            backtrack(i + 1, cur + s[i])
    backtrack(0, "")
    return res

